To implement a dictionary using a binary search tree (BST) in C++, we can create a simple command-line application that allows users to insert words and their definitions, look up words, delete words, and print the entire dictionary. Below is a detailed explanation and the corresponding C++ code.

---

### **Key Features:**
1. **Insertion:** Add words and their definitions into the BST.
2. **Lookup:** Search for a word and retrieve its definition.
3. **Deletion:** Remove a word and its definition from the BST.
4. **Display:** Print all words and their definitions in the dictionary.

---

### **Data Structures:**
- **Node:** Represents a node in the BST.
- **BST:** A class to manage the BST operations.
- **Dictionary:** A class to manage the dictionary operations (insert, lookup, delete, display).

---

### **C++ Code:**

```cpp
#include <iostream>
#include <string>
#include <map>
#include <vector>
#include <sstream>
#include <iomanip>
#include <algorithm>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(const string& w, const string& d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class
class BST {
public:
    BST() : root(nullptr) {}

    ~BST() {
        deleteTree(root);
    }

    void insert(const string& word, const string& definition) {
        if (root == nullptr) {
            root = new Node(word, definition);
            return;
        }
        insertNode(root, word, definition);
    }

    void insertNode(Node* node, const string& word, const string& definition) {
        if (word < node->word) {
            if (node->left == nullptr) {
                node->left = new Node(word, definition);
            } else {
                insertNode(node->left, word, definition);
            }
        } else if (word > node->word) {
            if (node->right == nullptr) {
                node->right = new Node(word, definition);
            } else {
                insertNode(node->right, word, definition);
            }
        }
    }

    Node* search(const string& word) {
        return searchNode(root, word);
    }

    Node* searchNode(Node* node, const string& word) {
        if (node == nullptr) return nullptr;
        if (word == node->word) return node;
        if (word < node->word) return searchNode(node->left, word);
        else return searchNode(node->right, word);
    }

    void deleteNode(Node* node, const string& word) {
        if (node == nullptr) return;
        if (word < node->word) {
            deleteNode(node->left, word);
        } else if (word > node->word) {
            deleteNode(node->right, word);
        } else {
            // Found the node
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                node = temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                node = temp;
            } else {
                Node* temp = getSuccessor(node);
                node->word = temp->word;
                node->definition = temp->definition;
                deleteNode(node->right, temp->word);
            }
        }
    }

    Node* getSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void deleteWord(const string& word) {
        deleteNode(root, word);
    }

    void display() const {
        displayNode(root);
    }

    void displayNode(Node* node) const {
        if (node != nullptr) {
            displayNode(node->left);
            cout << setw(20) << left << node->word << " | " << node->definition << endl;
            displayNode(node->right);
        }
    }

private:
    Node* root;

    void deleteTree(Node* node) {
        if (node != nullptr) {
            deleteTree(node->left);
            deleteTree(node->right);
            delete node;
        }
    }
};

int main() {
    BST dictionary;
    string inputWord, inputDefinition;
    bool exit = false;

    cout << "Dictionary Management System\n";
    cout << "1. Insert Word\n";
    cout << "2. Lookup Word\n";
    cout << "3. Delete Word\n";
    cout << "4. Display Dictionary\n";
    cout << "5. Exit\n";
    cout << "Enter your choice: ";

    while (!exit) {
        int choice;
        cin >> choice;
        cin.ignore(); // To consume the newline

        switch (choice) {
            case 1:
                cout << "Enter word: ";
                getline(cin, inputWord);
                cout << "Enter definition: ";
                getline(cin, inputDefinition);
                dictionary.insert(inputWord, inputDefinition);
                break;
            case 2:
                cout << "Enter word to look up: ";
                getline(cin, inputWord);
                Node* result = dictionary.search(inputWord);
                if (result) {
                    cout << "Definition: " << result->definition << endl;
                } else {
                    cout << "Word not found." << endl;
                }
                break;
            case 3:
                cout << "Enter word to delete: ";
                getline(cin, inputWord);
                dictionary.deleteWord(inputWord);
                break;
            case 4:
                cout << "Dictionary:" << endl;
                dictionary.display();
                break;
            case 5:
                exit = true;
                break;
            default:
                cout << "Invalid choice. Please try again." << endl;
        }
    }

    return 0;
}
```

---

### **Explanation of Key Components:**
- **Node Structure:** Stores the word and its definition.
- **BST Operations:** `insert`, `search`, `delete`, and `display` manage the BST operations.
- **Display Function:** Prints the dictionary in a formatted manner.

---

### **Usage Example:**
```
Dictionary Management System
1. Insert Word
2. Lookup Word
3. Delete Word
4. Display Dictionary
5. Exit
Enter your choice: 1
Enter word: "apple" 
Enter definition: "a fruit"
Enter your choice: 1
Enter word: "banana" 
Enter definition: "a yellow fruit"
Enter your choice: 4
Dictionary:
apple | a fruit
banana | a yellow fruit
Enter your choice: 2
Enter word to look up: apple
Definition: a fruit
Enter your choice: 3
Enter word to delete: banana
Enter your choice: 4
Dictionary:
apple | a fruit
```

