using System;

class GolfGame
{
    public int[] HolePar { get; set; }
    public int[] HoleScores { get; set; }
    public int TotalScore { get; set; }
    public int ParTotal { get; set; }

    public GolfGame(int numHoles)
    {
        HolePar = new int[numHoles];
        HoleScores = new int[numHoles];
        TotalScore = 0;
        ParTotal = 0;
    }

    public void InputHolePar(int index, int par)
    {
        HolePar[index] = par;
        ParTotal += par;
    }

    public void InputHoleScore(int index, int score)
    {
        HoleScores[index] = score;
        TotalScore += score;
    }

    public void CalculateStats()
    {
        AverageScore = TotalScore / HoleScores.Length;
        BestScore = HoleScores.Max();
        WorstScore = HoleScores.Min();
    }

    public double AverageScore { get; private set; }
    public int BestScore { get; private set; }
    public int WorstScore { get; private set; }
}

class Program
{
