    {
        GolfGame game = new GolfGame(18); // 18 holes

        Console.WriteLine("Enter par for each hole:");
        for (int i = 0; i < 18; i++)
        {
            int par = int.Parse(Console.ReadLine());
            game.InputHolePar(i, par);
        }

        Console.WriteLine("Enter your score for each hole:");
        for (int i = 0; i < 18; i++)
        {
            int score = int.Parse(Console.ReadLine());
            game.InputHoleScore(i, score);
        }

        game.CalculateStats();

        Console.WriteLine("\nGame Summary:");
        Console.WriteLine($"Total Score: {game.TotalScore}");
        Console.WriteLine($"Par Total: {game.ParTotal}");
        Console.WriteLine($"Score Difference: {game.TotalScore - game.ParTotal}");
        Console.WriteLine($"Average Score per Hole: {game.AverageScore}");
        Console.WriteLine($"Best Hole: {game.BestScore}");
        Console.WriteLine($"Worst Hole: {game.WorstScore}");
    }
}
```

