# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles errors, and provides output in kilometers or miles.

---

## Features

- Accepts latitude and longitude for two locations.
- Calculates distance using the Haversine formula.
- Outputs location names and distance in kilometers or miles.
- Handles invalid input and unavailable location data.
- Includes tests and examples.

---

## Script

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Define constants
my $KILOMETERS = 1;
my $MILES = 2;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Radius of Earth in kilometers

    my $dlat = deg2rad($lat2 - $lat1);
    my $dlong = deg2rad($lon2 - $lat2);

    my $a = sin($dlat/2) ** 2 + cos(deg2rad($lat1)) * cos(deg2rad($lat2)) * sin($dlong/2);
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub deg2rad {
    return radians * pi / 180;
}

# Get location names from a JSON file
sub get_location_names {
    my $json_file = 'locations.json';
    my $data = read_json($json_file);
    return $data->{locations};
}

# Read JSON file
sub read_json {
    my $file = shift;
    open(my $fh, '<', $file) or die "Cannot open $file: $!";
    my $content = do { local $/; <$fh> };
    close $fh;
    return $content;
}

# Main script
sub main {
    my ($lat1, $lon1, $lat2, $lon2) = @ARGV;

    # Validate input
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Usage: $0 <lat1> <lon1> <lat2> <lon2>";
    }

    # Convert inputs to floats
    $lat1 = parseFloat($lat1);
    $lon1 = parseFloat($lon1);
    $lat2 = parseFloat($lat2);
    $lon2 = parseFloat($lon2);

    # Validate coordinates
    if (!is_valid_coordinate($lat1) || !is_valid_coordinate($lon1) || !is_valid_coordinate($lat2) || !is_valid_coordinate($lon2)) {
        die "Invalid coordinates: Latitude and longitude must be between -90 and 90, and longitude between -180 and 180.";
    }

    # Get location names
    my @locations = get_location_names();
    my %locations = map { $_ => 1 } @locations;

    # Calculate distance
    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);

    # Output
    print "Distance between $locations{$lat1} and $locations{$lat2} is $distance km\n";

    # Optional: Output in miles
    if ($ARGV[4] eq $MILES) {
        my $distance_miles = $distance * 0.621371;
        print "Distance between $locations{$lat1} and $locations{$lat2} is $distance_miles mi\n";
    }
}

# Helper function to check if a coordinate is valid
sub is_valid_coordinate {
    my ($coord) = @_;
    return $coord >= -90 && $coord <= 90 && $coord >= -180 && $coord <= 180;
}

# Helper function to convert string to float
sub parseFloat {
    return sprintf("%.6f", shift);
}

# Main execution
main();
```

