```swift
// BinarySearchTree.swift
import Foundation

// Define a Node struct to represent each node in the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, handle deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right)!
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node
        var successor = nil

        while current != nil {
            successor = current!
            current = current!.left
        }

        return successor
    }

    // Traversal functions
    // Pre-order traversal: visit node, then left, then right
    func preOrderTraversal() {
        preOrderTraverse(root)
    }

    // Helper function for pre-order traversal
    private func preOrderTraverse(_ node: Node?) {
        if node != nil {
            print(node!.value, terminator: " ")
            preOrderTraverse(node!.left)
            preOrderTraverse(node!.right)
        }
    }

    // In-order traversal: left, visit node, right
    func inOrderTraversal() {
        inOrderTraverse(root)
    }

    // Helper function for in-order traversal
    private func inOrderTraverse(_ node: Node?) {
        if node != nil {
            inOrderTraverse(node!.left)
            print(node!.value, terminator: " ")
            inOrderTraverse(node!.right)
        }
    }

    // Post-order traversal: left, right, visit node
    func postOrderTraversal() {
        postOrderTraverse(root)
    }

    // Helper function for post-order traversal
    private func postOrderTraverse(_ node: Node?) {
        if node != nil {
            postOrderTraverse(node!.left)
            postOrderTraverse(node!.right)
            print(node!.value, terminator: " ")
        }
    }
}
```

### Explanation of Key Features:

- **Node Structure**: Each node contains a value and references to its left and right children.
- **Insertion**: The `insert` method adds a new node to the correct position in the BST, ensuring the BST properties are maintained.
- **Deletion**: The `delete` method removes a node while preserving the BST structure. Special handling is done for nodes with two children.
- **Traversal**:
  - **Pre-order**: Visit node, then left, then right.
  - **In-order**: Left, visit node, right.
  - **Post-order**: Left, right, visit node.

### Efficiency:
- Insertion and deletion are **O(log n)** in average case (for balanced BSTs).
- Traversal is **O(n)** in the worst case (linear time for unbalanced BSTs).

This implementation is clean, efficient, and follows standard BST principles.

